Here's a simple C++ function that converts a basic **Markdown-formatted string** into **HTML-formatted text**. This implementation supports:

- **Bold text** (`**text**` → `<strong>text</strong>`)
- *Italic text* (`*text*` → `<em>text</em>`)
- Headings (`# Heading` → `<h1>Heading</h1>`, `## Heading` → `<h2>Heading</h2>`, etc.)
- Unordered lists (`- item` → `<ul><li>item</li></ul>`)
- Ordered lists (`1. item` → `<ol><li>item</li></ol>`)

> ⚠️ This is a **basic** implementation and does **not** handle all Markdown syntax or edge cases. For a full Markdown parser, consider using a library like [markdown.cpp](https://github.com/jbeder/markdown) or [pugixml](https://github.com/zeux/pugixml).

---

### ✅ C++ Function: Markdown to HTML

```cpp
#include <string>
#include <sstream>
#include <vector>
#include <algorithm>

std::string markdownToHtml(const std::string& markdown) {
    std::string html;
    std::istringstream iss(markdown);
    std::string line;
    bool inList = false;
    int listLevel = 0;

    while (std::getline(iss, line)) {
        // Trim leading and trailing whitespace
        line.erase(0, line.find_first_not_of(" \t"));
        line.erase(line.find_last_not_of(" \t") + 1);

        // Check for heading
        size_t hashPos = line.find('#');
        if (hashPos != std::string::npos) {
            int level = 0;
            while (hashPos < line.length() && line[hashPos] == '#') {
                ++level;
                ++hashPos;
            }
            if (hashPos < line.length() && line[hashPos] == ' ') {
                std::string heading = line.substr(hashPos);
                html += "<h" + std::to_string(level) + ">" + heading + "</h" + std::to_string(level) + ">\n";
                continue;
            }
        }

        // Check for list items
        if (line[0] == '-' || line[0] == '*') {
            if (!inList) {
                html += "<ul>\n";
                inList = true;
            }
            std::string item = line.substr(2);
            html += "  <li>" + item + "</li>\n";
            continue;
        }

        if (line[0] == '1' && line[1] == '.' && line[2] == ' ') {
            if (!inList) {
                html += "<ol>\n";
                inList = true;
            }
            std::string item = line.substr(4);
            html += "  <li>" + item + "</li>\n";
            continue;
        }

        // Check for bold and italic
        std::string processedLine = line;
        size_t boldStart = 0;
        while ((boldStart = processedLine.find("**", boldStart)) != std::string::npos) {
            size_t boldEnd = processedLine.find("**", boldStart + 2);
            if (boldEnd != std::string::npos) {
                std::string text = processedLine.substr(boldStart + 2, boldEnd - boldStart - 2);
                processedLine.replace(boldStart, boldEnd - boldStart + 2, "<strong>" + text + "</strong>");
                boldStart += 14; // length of "<strong>text</strong>"
            } else {
                break;
            }
        }

        size_t italicStart = 0;
        while ((italicStart = processedLine.find("*", italicStart)) != std::string::npos) {
            size_t italicEnd = processedLine.find("*", italicStart + 1);
            if (italicEnd != std::string::npos) {
                std::string text = processedLine.substr(italicStart + 1, italicEnd - italicStart - 1);
                processedLine.replace(italicStart, italicEnd - italicStart + 1, "<em>" + text + "</em>");
                italicStart += 10; // length of "<em>text</em>"
            } else {
                break;
            }
        }

        html += processedLine + "\n";
    }

    if (inList) {
        html += "</ul>\n";
    }

    return html;
}
```

---

### ✅ Example Usage

```cpp
#include <iostream>

int main() {
    std::string markdown = R"(
# Heading 1
## Heading 2

**Bold text** and *italic text*.

- Item 1
- Item 2
- Item 3

1. First item
2. Second item
3. Third item
)";

    std::string html = markdownToHtml(markdown);
    std::cout << html;
    return 0;
}
```

---

### ✅ Output

```html
<h1>Heading 1</h1>
<h2>Heading 2</h2>

<strong>Bold text</strong> and <em>italic text</em>.

<ul>
  <li>Item 1</li>
  <li>Item 2</li>
  <li>Item 3</li>
</ul>

<ol>
  <li>First item</li>
  <li>Second item</li>
  <li>Third item</li>
</ol>
```

---

### 📌 Notes

- This is a **very basic** parser and does **not** support nested lists, code blocks, links, images, or other Markdown features.
- For a full Markdown parser, consider using a library like [markdown.cpp](https://github.com/jbeder/markdown) or [pugixml](https://github.com/zeux/pugixml).

